/**
 * Busca tinta tintometrica com prioridade de linha/acabamento e retorna melhor opcao com preco/estoque.
 * Use esta ferramenta para cores nao-brancas.
 *
 * @param {string} cliente - alberto ou marcel (default: marcel)
 * @param {string} loja - codigo/nome da loja (opcional)
 * @param {string} marca - tmc|sherwin|suvinil|coral (obrigatorio)
 * @param {string} cor - nome da cor (obrigatorio)
 * @param {string} volume - 0.9L|3.6L|18L (obrigatorio)
 * @param {string} acabamento - fosco|acetinado|semibrilho|brilhante (opcional)
 * @param {string} linha - linha exata prioritaria (opcional)
 * @param {string} base - agua|solvente (opcional, usado em esmalte)
 * @param {string} superficie - parede|metal|madeira|piso|fachada (opcional)
 * @param {string} cenario - linha_especifica|generico (opcional)
 * @returns {Promise<string>}
 */
async function tintometricoCodeTool(cliente, loja, marca, cor, volume, acabamento, linha, base, superficie, cenario) {
  const strip = (v) => String(v || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '');
  const norm = (v) => strip(v).toLowerCase().trim();
  const up = (v) => strip(v).toUpperCase().trim();

  const clients = {
    alberto: {
      url: 'http://159.112.189.1:25046',
      lojas: {
        '173': '173', 'guedala': '173', 'jardim guedala': '173',
        '191': '191', 'mascote': '191', 'vila mascote': '191',
        '131': '131', 'chacara': '131', 'chacara santo antonio': '131',
        '132': '132', 'andrade': '132', 'vila andrade': '132',
        '067': '067', 'morumbi': '067', 'portal morumbi': '067',
      },
      lojaDefault: '173',
      empresaPreco: '173',
    },
    marcel: {
      url: 'http://159.112.189.1:25189',
      lojas: {
        '199': '199', 'guarulhos': '199',
        '037': '037', 'tatuape': '037',
        '179': '179', 'analia': '179', 'analia franco': '179',
      },
      lojaDefault: '179',
      empresaPreco: '179',
    },
  };

  const marcas = [
    { sigla: 'CIM', nomes: ['coral', 'cim'] },
    { sigla: 'SHW', nomes: ['tmc', 'sherwin', 'sherwin williams', 'sw', 'tintas mc', 'shw'] },
    { sigla: 'SUV', nomes: ['suvinil', 'suv'] },
  ];

  const acabamentoMap = {
    fosco: ['fosco', 'matte'],
    matte: ['fosco', 'matte'],
    acetinado: ['acetinado', 'acetinada', 'seda', 'sedoso'],
    semibrilho: ['semibrilho', 'diamante'],
    brilhante: ['brilhante', 'brilho'],
  };

  // Compatibilidade: alguns calls chegam como unico campo "query" (texto ou JSON).
  try {
    const raw = ($input && $input.item && $input.item.json) ? $input.item.json : {};
    const needsHydration = !marca || !cor || !volume;

    if (needsHydration && raw && raw.query) {
      let parsed = {};
      let q = raw.query;

      if (typeof q === 'string') {
        const txt = q.trim();
        if (txt.startsWith('{') && txt.endsWith('}')) {
          try { q = JSON.parse(txt); } catch (_) {}
        }
      }

      if (q && typeof q === 'object' && !Array.isArray(q)) {
        parsed = q;
      } else if (typeof q === 'string') {
        // Exemplo: "cliente: marcel, marca: suvinil, cor: palha, volume: 3.6L"
        for (const part of q.split(',')) {
          const idx = part.indexOf(':');
          if (idx <= 0) continue;
          const k = norm(part.slice(0, idx)).replace(/[^a-z]/g, '');
          const v = part.slice(idx + 1).trim().replace(/^['"]|['"]$/g, '');
          if (!k || !v) continue;
          parsed[k] = v;
        }
      }

      const pick = (...keys) => {
        for (const key of keys) {
          const match = Object.keys(parsed).find((k) => norm(k).replace(/[^a-z]/g, '') === key);
          if (match && parsed[match] !== undefined && parsed[match] !== null && String(parsed[match]).trim() !== '') {
            return String(parsed[match]).trim();
          }
        }
        return '';
      };

      if (!cliente) cliente = pick('cliente');
      if (!loja) loja = pick('loja');
      if (!marca) marca = pick('marca');
      if (!cor) cor = pick('cor');
      if (!volume) volume = pick('volume');
      if (!acabamento) acabamento = pick('acabamento');
      if (!linha) linha = pick('linha');
      if (!base) base = pick('base');
      if (!superficie) superficie = pick('superficie', 'superfcie');
      if (!cenario) cenario = pick('cenario');
    }
  } catch (_) {}

  const clientKey = norm(cliente) || 'marcel';
  const cfg = clients[clientKey];
  if (!cfg) {
    return JSON.stringify({ ok: false, erro: 'Cliente invalido. Use alberto ou marcel.' }, null, 2);
  }

  const marcaKey = norm(marca);
  const marcaObj = marcas.find((m) => m.nomes.includes(marcaKey));
  if (!marcaObj) {
    return JSON.stringify({ ok: false, erro: 'Marca invalida. Use tmc/sherwin, suvinil ou coral.' }, null, 2);
  }

  const lojaNorm = norm(loja);
  const lojaCodigo = (function resolveLoja() {
    if (!lojaNorm) return cfg.lojaDefault;
    const key = Object.keys(cfg.lojas).find((k) => norm(k).includes(lojaNorm) || lojaNorm.includes(norm(k)));
    return key ? cfg.lojas[key] : cfg.lojaDefault;
  })();

  const corNorm = norm(cor);
  if (!corNorm) {
    return JSON.stringify({ ok: false, erro: 'Cor obrigatoria.' }, null, 2);
  }
  if (corNorm === 'branco' || corNorm === 'branca') {
    return JSON.stringify({ ok: false, erro: 'Para branco/branca use buscar_produto_mc.' }, null, 2);
  }

  const volRaw = String(volume || '').replace(',', '.');
  const volNum = parseFloat(volRaw.replace(/[^\d.]/g, '')) || 3.6;
  const embalagemEsperada = volNum >= 16 ? 'LATA' : volNum >= 2 ? 'GALAO' : 'LITRO';

  const headers = {
    accept: 'application/json',
    Authorization: 'Basic ' + Buffer.from('TESTE:123').toString('base64'),
  };

  const n8nHttp =
    (typeof $httpRequest === 'function')
      ? $httpRequest
      : ((typeof this !== 'undefined' && this && this.helpers && typeof this.helpers.httpRequest === 'function')
        ? this.helpers.httpRequest.bind(this)
        : null);

  async function requestJson(method, url, body) {
    if (typeof fetch === 'function') {
      const resp = await fetch(url, {
        method,
        headers: body === undefined ? headers : { ...headers, 'Content-Type': 'application/json' },
        body: body === undefined ? undefined : JSON.stringify(body),
      });
      const text = await resp.text();
      let data = {};
      try { data = text ? JSON.parse(text) : {}; } catch (_) { data = { raw: text }; }
      if (!resp.ok) {
        throw new Error(method + ' ' + resp.status + ': ' + JSON.stringify(data).slice(0, 200));
      }
      return data;
    }

    if (n8nHttp) {
      const options = {
        method,
        url,
        headers: body === undefined ? headers : { ...headers, 'Content-Type': 'application/json' },
        json: true,
        timeout: 60000,
      };
      if (body !== undefined) options.body = body;
      try {
        return await n8nHttp(options);
      } catch (err) {
        const detail =
          (err && err.response && err.response.body)
            ? JSON.stringify(err.response.body).slice(0, 300)
            : String((err && err.message) || err);
        throw new Error(method + ' ' + url + ' -> ' + detail);
      }
    }

    const transport = url.startsWith('https') ? require('https') : require('http');
    return await new Promise((resolve, reject) => {
      const u = new URL(url);
      const payload = body === undefined ? null : JSON.stringify(body);
      const req = transport.request({
        hostname: u.hostname,
        port: u.port || (u.protocol === 'https:' ? 443 : 80),
        path: u.pathname + u.search,
        method,
        headers: payload
          ? { ...headers, 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(payload) }
          : headers,
      }, (res) => {
        let d = '';
        res.on('data', (c) => { d += c; });
        res.on('end', () => {
          let parsed = {};
          try { parsed = d ? JSON.parse(d) : {}; } catch (_) { parsed = { raw: d }; }
          if (res.statusCode < 200 || res.statusCode >= 300) {
            return reject(new Error(method + ' ' + url + ' -> HTTP ' + res.statusCode + ': ' + JSON.stringify(parsed).slice(0, 260)));
          }
          resolve(parsed);
        });
      });
      req.on('error', reject);
      if (payload) req.write(payload);
      req.end();
    });
  }

  async function getJson(url) {
    return await requestJson('GET', url);
  }

  async function postJson(url, body) {
    return await requestJson('POST', url, body);
  }

  function scoreCor(corItem, corBusca) {
    const cn = norm(corItem);
    const cb = norm(corBusca);
    if (cn === cb) return 1000;
    if (cn.startsWith(cb + ' ') || cn.startsWith(cb + '-')) return 900;
    if (cn.startsWith(cb)) return 850;
    if (cn.endsWith(' ' + cb)) return 800;
    if (cn.includes(cb)) return 500;
    return 0;
  }

  function fitAcabamento(texto, alvo) {
    if (!alvo) return true;
    const item = norm(texto);
    const key = norm(alvo).split(' ')[0];
    const words = acabamentoMap[key] || [key];
    return words.some((w) => item.includes(w));
  }

  function fitLinha(texto, alvo) {
    if (!alvo) return true;
    const item = up(texto);
    const line = up(alvo);
    const parts = line.split(' ').filter(Boolean);
    if (item.includes(line)) return true;
    return parts.length > 1 && parts.every((p) => item.includes(p));
  }

  const baseUrl = cfg.url;
  const sigla = marcaObj.sigla;

  try {
    const coresUrl = baseUrl + '/V2/tintas/cores/' + sigla
      + '?cor=' + encodeURIComponent(corNorm)
      + '&corComRgb=false&page=0&size=500&codigoEmpresa=' + lojaCodigo;
    const coresResp = await getJson(coresUrl);
    const topCores = (coresResp.content || [])
      .map((c) => ({ ...c, score: scoreCor(c.cor, corNorm) }))
      .filter((c) => c.score > 0)
      .sort((a, b) => b.score - a.score || a.cor.length - b.cor.length)
      .slice(0, 5);

    if (!topCores.length) {
      return JSON.stringify({ ok: false, erro: 'Cor nao encontrada no tintometrico.' }, null, 2);
    }

    const embalagens = [];
    for (const c of topCores) {
      const embUrl = baseUrl + '/V2/tintas/embalagem/' + sigla
        + '?codigoCor=' + encodeURIComponent(c.codigoCor)
        + '&codigoRgb=' + encodeURIComponent(c.rgb)
        + '&cor=' + encodeURIComponent(c.cor);
      const embResp = await getJson(embUrl);
      const embs = Array.isArray(embResp) ? embResp : (embResp.content || []);
      for (const e of embs) {
        const emb = up(e.embalagemSimplificada || e.embalagem);
        if (emb === embalagemEsperada || emb.includes(embalagemEsperada)) {
          embalagens.push({
            codigoCor: c.codigoCor,
            rgb: c.rgb,
            cor: c.cor,
            embalagem: e.embalagemSimplificada || e.embalagem,
          });
        }
      }
    }

    if (!embalagens.length) {
      return JSON.stringify({
        ok: false,
        erro: 'Nao ha embalagem compativel para o volume pedido.',
        volume: volume,
        embalagem_esperada: embalagemEsperada,
      }, null, 2);
    }

    let candidatos = [];
    for (const e of embalagens) {
      const acbUrl = baseUrl + '/V2/tintas/acabamentos/' + sigla
        + '?codigoCor=' + encodeURIComponent(e.codigoCor)
        + '&codigoRgb=' + encodeURIComponent(e.rgb)
        + '&cor=' + encodeURIComponent(e.cor)
        + '&embalagem=' + encodeURIComponent(e.embalagem);
      const acbResp = await getJson(acbUrl);
      const acbs = Array.isArray(acbResp) ? acbResp : (acbResp.content || []);
      for (const a of acbs) {
        candidatos.push({
          cor: e.cor,
          embalagem: e.embalagem,
          acabamento_api: a.acabamento || '',
          chaveCitel: String(a.chaveCitel || ''),
        });
      }
    }

    if (norm(linha)) {
      const linhaFiltrada = candidatos.filter((c) => fitLinha(c.acabamento_api, linha));
      if (linhaFiltrada.length) candidatos = linhaFiltrada;
    }
    if (norm(acabamento)) {
      const acbFiltrado = candidatos.filter((c) => fitAcabamento(c.acabamento_api, acabamento));
      if (acbFiltrado.length) candidatos = acbFiltrado;
    }
    if (norm(base)) {
      const b = norm(base);
      const baseFiltrada = candidatos.filter((c) => norm(c.acabamento_api).includes(b));
      if (baseFiltrada.length) candidatos = baseFiltrada;
    }

    const seen = new Set();
    candidatos = candidatos.filter((c) => c.chaveCitel && !seen.has(c.chaveCitel) && seen.add(c.chaveCitel));

    const precificados = [];
    const postErros = [];
    for (const c of candidatos.slice(0, 30)) {
      const payloads = [
        {
          codigoCliente: '00000001',
          codigoEmpresa: cfg.empresaPreco,
          hashesMd5: [c.chaveCitel],
          idPro: sigla,
        },
        {
          codigoCliente: '00000001',
          codigoEmpresa: cfg.empresaPreco,
          hashesMd5: [c.chaveCitel],
        },
      ];

      let precoResp = null;
      let ultimoErro = null;
      for (const payload of payloads) {
        try {
          precoResp = await postJson(baseUrl + '/V2/tintas/carregar/dados', payload);
          ultimoErro = null;
          break;
        } catch (err) {
          ultimoErro = String(err.message || err);
        }
      }

      if (!precoResp) {
        if (ultimoErro && postErros.length < 5) {
          postErros.push({
            chaveCitel: c.chaveCitel,
            linha: c.acabamento_api,
            erro: ultimoErro,
          });
        }
        continue;
      }

      const itens = Array.isArray(precoResp) ? precoResp : (precoResp.content || [precoResp]);
      for (const p of itens) {
        const preco = Number(p.preco1 || 0);
        const estoque = Number(p.estoqueDisponivel || 0);
        if (preco > 0.1) {
          precificados.push({
            cor: c.cor,
            linha: c.acabamento_api,
            embalagem: c.embalagem,
            preco,
            estoque,
            chaveCitel: c.chaveCitel,
          });
        }
      }
    }

    if (!precificados.length) {
      return JSON.stringify({
        ok: false,
        erro: 'Nenhum candidato com preco valido retornado.',
        diagnostico: {
          candidatos_testados: Math.min(candidatos.length, 30),
          erros_post_exemplo: postErros,
        },
      }, null, 2);
    }

    precificados.sort((a, b) => {
      if (norm(linha)) {
        const aHit = fitLinha(a.linha, linha) ? 1 : 0;
        const bHit = fitLinha(b.linha, linha) ? 1 : 0;
        if (bHit !== aHit) return bHit - aHit;
      }
      if (norm(acabamento)) {
        const aHit = fitAcabamento(a.linha, acabamento) ? 1 : 0;
        const bHit = fitAcabamento(b.linha, acabamento) ? 1 : 0;
        if (bHit !== aHit) return bHit - aHit;
      }
      if (b.estoque !== a.estoque) return b.estoque - a.estoque;
      return a.preco - b.preco;
    });

    // === FORMATAR MENSAGEM (mesmo formato do TINTOMETRICO_MULTITENANT) ===
    function volumeByEmbalagem(e) {
      const v = (e || '').toUpperCase();
      if (v.includes('LATA')) return '16 L';
      if (v.includes('GALAO') || v.includes('GALÃO')) return '3,2 L';
      if (v.includes('LITRO')) return '0,8 L';
      return '';
    }

    function fmtProduto(p, volRaw, aviso) {
      const volStr = volumeByEmbalagem(p.embalagem) || volRaw || '';
      const desc = (sigla + ' ' + p.cor + ' ' + p.linha + ' ' + p.embalagem + ' ' + volStr).replace(/\s+/g, ' ').trim();
      const precoBRL = p.preco.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL' });
      const disp = p.estoque > 0 ? '✅ Disponível em estoque' : '⚠️ Sob consulta';
      let msg = '• ' + desc + '\n💰 Preço: ' + precoBRL + '\n📦 ' + disp;
      if (aviso) msg += '\n\n' + aviso;
      else msg += '\n\nPosso seguir com esse item?';
      return msg;
    }

    const best = precificados[0];

    // Se pediu linha especifica e nao encontrou
    if (norm(linha)) {
      const acab = (best.linha || '').toUpperCase();
      const linhaUp = (linha || '').toUpperCase().trim();
      const words = linhaUp.split(' ').filter(Boolean);
      const found = acab.includes(linhaUp) || (words.length > 1 && words.every(w => acab.includes(w)));
      if (!found) {
        const aviso = '⚠️ Nao encontrei exatamente a linha "' + linha + '". Opcao disponivel mais proxima:';
        return fmtProduto(best, volume, aviso);
      }
    }

    return fmtProduto(best, volume);
  } catch (err) {
    return JSON.stringify({ ok: false, erro: String(err.message || err) }, null, 2);
  }
}

const payload = (() => {
  if (typeof query !== 'undefined' && query !== null) {
    if (typeof query === 'object') return query;
    if (typeof query === 'string') return { query };
  }
  if (typeof $input !== 'undefined' && $input && $input.item && $input.item.json) {
    return $input.item.json;
  }
  return {};
})();

return await tintometricoCodeTool(
  payload.cliente,
  payload.loja,
  payload.marca,
  payload.cor,
  payload.volume,
  payload.acabamento,
  payload.linha,
  payload.base,
  payload.superficie,
  payload.cenario,
);
